Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, timeouts, and cancellation testing:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)] // Fails test if it hangs beyond 5s
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenCanceled()
    {
        // Handler that delays so cancellation can fire
        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();

        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable mock handler
    private class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            cancellationToken.ThrowIfCancellationRequested();

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Purpose |
|---------|---------|
| `async Task` return type | MSTest natively awaits the test |
| `[Timeout(5000)]` | Guards against deadlocks/hangs |
| `CancellationTokenSource` | Verifies cancellation propagation |
| `Assert.ThrowsExceptionAsync` | Proper async exception assertion |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; controls HTTP layer directly |

**Tips:**
- Never use `.Result` or `.Wait()` in async tests — always `await`.
- `[Timeout]` is especially important for async tests to catch accidental deadlocks.
- Pre-canceling the token (`cts.Cancel()` before the call) is the simplest way to verify cancellation support without races.
